// Both describe the same object shape
interface UserInterface {
  id: number;
  name: string;
}

type UserType = {
  id: number;
  name: string;
};

// Both are structurally equivalent — TypeScript checks shape, not name
const a: UserInterface = { id: 1, name: 'Alice' };
const b: UserType       = { id: 2, name: 'Bob' };

// Assignable to each other — structural typing
const c: UserInterface = b; // OK
const d: UserType       = a; // OK

// Original declaration (could be in a library)
interface Window {
  analytics: { trackEvent(name: string): void };
}

// Augment it in your own code — TypeScript merges both
interface Window {
  featureFlags: Record<string, boolean>;
}

// window now has both analytics and featureFlags — no error

// Example: augmenting Express Request
declare global {
  namespace Express {
    interface Request {
      currentUser?: { id: number; role: string };
    }
  }
}

interface Serializable {
  serialize(): string;
  deserialize(data: string): void;
}

// Both interface and type alias work with implements
class UserModel implements Serializable {
  constructor(public id: number, public name: string) {}

  serialize(): string {
    return JSON.stringify({ id: this.id, name: this.name });
  }

  deserialize(data: string): void {
    const parsed = JSON.parse(data);
    this.id   = parsed.id;
    this.name = parsed.name;
  }
}

// type alias also works with implements
type Loggable = {
  log(): void;
};

class Service implements Loggable {
  log(): void { console.log('Service running'); }
}

// Union — interface CANNOT do this
type StringOrNumber = string | number;
type Result<T> =
  | { ok: true;  data: T }
  | { ok: false; error: string };

function process(input: StringOrNumber): string {
  return typeof input === 'string' ? input.toUpperCase() : input.toFixed(2);
}

// Intersection — can merge two anonymous shapes
type Named   = { name: string };
type Aged    = { age: number };
type Person  = Named & Aged; // { name: string; age: number }

// interface can only extend named interfaces
interface PersonInterface extends Named, Aged {}
// but that is syntactically heavier for ad-hoc composition

// Primitive alias — useful for branded types
type UserId   = number & { readonly __brand: unique symbol };
type Username  = string;

// Tuple alias — precise, fixed-length arrays
type Point2D   = [number, number];
type RGB        = [red: number, green: number, blue: number];
type Pair<T, U> = [T, U];

const origin: Point2D = [0, 0];
const red:    RGB     = [255, 0, 0];

// Template literal alias
type EventName = 'click' | 'focus' | 'blur';
type HandlerKey = `on${Capitalize<EventName>}`;
// 'onClick' | 'onFocus' | 'onBlur'

// Mapped type alias — generate object from a literal union
type Flags<T extends string> = { [K in T]: boolean };
type PermissionFlags = Flags<'read' | 'write' | 'delete'>;
// { read: boolean; write: boolean; delete: boolean }

// Conditional types require type alias — no interface equivalent
type IsArray<T> = T extends any[] ? true : false;
type R1 = IsArray<string[]>;  // true
type R2 = IsArray<string>;    // false

// Unwrap a Promise
type Awaited<T> = T extends Promise<infer U> ? Awaited<U> : T;
type Resolved = Awaited<Promise<Promise<number>>>; // number

// Filter a union by shape
type OnlyObjects<T> = T extends object ? T : never;
type Mixed = string | number | { id: number };
type ObjectsOnly = OnlyObjects<Mixed>; // { id: number }

// Both support generics identically
interface Repository<T> {
  findById(id: number): Promise<T>;
  save(entity: T): Promise<T>;
  delete(id: number): Promise<void>;
}

type ApiResponse<T> = {
  data: T;
  status: number;
  message: string;
};

// Both can be used as constraints
function first<T>(arr: T[]): T {
  return arr[0];
}

interface Base     { id: number }
type    Named    = { name: string };

// interface extending interface — standard
interface Entity extends Base { createdAt: Date }

// interface extending type alias — legal
interface NamedEntity extends Named { id: number }

// type alias intersecting interface — legal
type FullEntity = Base & Named & { role: string };

// type alias intersecting type alias — legal
type A = { x: number };
type B = { y: number };
type C = A & B; // { x: number; y: number }

// Angular: prefer interface for service contracts
interface AuthService {
  readonly currentUser: Signal<User | null>;
  login(credentials: Credentials): Observable<void>;
  logout(): void;
}

// Angular: prefer type alias for component state unions
type LoadState = 'idle' | 'loading' | 'loaded' | 'error';

@Component({ selector: 'app-list', template: '' })
class ListComponent {
  state = signal<LoadState>('idle');
  items = signal<Item[]>([]);
}

// Angular: prefer type alias for HTTP response shapes when using union
type ApiResult<T> =
  | { success: true;  data: T }
  | { success: false; error: string; code: number };

// Angular: prefer interface for DI tokens
interface ConfigService {
  get<T>(key: string): T;
}

const CONFIG_SERVICE = new InjectionToken<ConfigService>('ConfigService');

// Two files in the same module — interface declarations merge silently
// file-a.ts
interface Config { host: string }

// file-b.ts (same scope)
interface Config { port: number }

// merged result: { host: string; port: number }
// This can be surprising — the second declaration ADDS, not replaces.

// type alias — cannot accidentally merge; second definition is a compile error:
// type Config = { host: string }    // first def
// type Config = { port: number }    // Error: Duplicate identifier 'Config'.
// Use type aliases when you want strict, non-mergeable definitions.

// Direct self-reference in type alias is forbidden
// type BadList<T> = { value: T; next: BadList<T> } | null;  // Error in older TS

// Legal pattern: indirect self-reference via object property
type List<T> = { value: T; next: List<T> | null };  // OK in TS 3.7+

// interface has always supported self-reference
interface Node<T> {
  value: T;
  next: Node<T> | null;  // always legal
}

interface UserInterface { id: number; name: string }
type     UserType      = { id: number; name: string };

function greetInterface(u: UserInterface): void { console.log(u.name); }
function greetType(u: UserType): void            { console.log(u.name); }

// Calling with wrong type
greetInterface({ id: 1, nme: 'Alice' });
// Error: Argument of type '{ id: number; nme: string; }' is not assignable
//        to parameter of type 'UserInterface'.
//        Object literal may only specify known properties...

greetType({ id: 1, nme: 'Alice' });
// Same error — but the type parameter shows as:
//        '{ id: number; name: string }'  (expanded)
// With interfaces, longer chains stay readable because names are preserved.

// Complex generics — interface names help
interface Page<T> { items: T[]; total: number; page: number }
// Hover shows: Page<User>

type PageType<T> = { items: T[]; total: number; page: number };
// Hover may show: { items: User[]; total: number; page: number }

// TypeScript shows interface names in tooltips, which keeps long generic chains readable
interface ApiResponse<T> {
  data: T;
  status: 200 | 400 | 401 | 404 | 500;
  requestId: string;
}

interface PaginatedUsers extends ApiResponse<UserInterface[]> {
  page: number;
  pageSize: number;
}

// Hovering over a PaginatedUsers variable shows: PaginatedUsers
// rather than: { data: UserInterface[]; status: 200 | 400 | 401 | 404 | 500;
//               requestId: string; page: number; pageSize: number }

// interface → type alias: always safe for object shapes
interface ProductInterface {
  id: number;
  name: string;
  price: number;
  category: string;
}

// Equivalent type alias
type ProductType = {
  id: number;
  name: string;
  price: number;
  category: string;
};

// type alias → interface: only works for plain object shapes
type SimpleAlias = { x: number; y: number };

// CONVERTIBLE — plain object shape
interface SimpleInterface { x: number; y: number }

// NOT CONVERTIBLE — union
type LoadState = 'idle' | 'loading' | 'error';
// interface LoadState = 'idle' | 'loading' | 'error'; // SYNTAX ERROR

// NOT CONVERTIBLE — tuple
type Pair = [string, number];
// interface Pair = [string, number]; // SYNTAX ERROR

// NOT CONVERTIBLE — mapped type
type ReadonlyProduct = Readonly<ProductType>;
// interface cannot derive from a mapped utility type directly

// Prefer interface extends over type intersection in large codebases
// for better compiler caching

// Slower: type intersection — must be re-expanded each time it is checked
type EntityType    = { id: number; createdAt: Date };
type ProductType2  = EntityType & { name: string; price: number };
type OrderType     = EntityType & { items: ProductType2[]; total: number };

// Faster: interface inheritance — TypeScript caches the result by name
interface EntityInterface { id: number; createdAt: Date }
interface ProductInterface extends EntityInterface { name: string; price: number }
interface OrderInterface   extends EntityInterface { items: ProductInterface[]; total: number }

// In practice this matters only at tens of thousands of type usages,
// but it is the idiomatic reason to prefer interface for hierarchical models.

import type { Equal, Expect } from '@type-challenges/utils';

interface UserIF { id: number; name: string }
type UserT = { id: number; name: string };

// Type-level test: are they structurally equal?
type _test1 = Expect<Equal<UserIF, UserT>>;  // passes — same shape

// In unit tests, casting to interface is identical to casting to type alias
function buildUser(): UserIF {
  return { id: 1, name: 'Alice' };
}

// Both work as return type constraints
function buildUserT(): UserT {
  return { id: 2, name: 'Bob' };
}

// Angular mock factories work identically with both
const mockUser: UserIF = { id: 0, name: 'Test User' };
const mockUserT: UserT = { id: 0, name: 'Test User' };

// Jasmine / Jest: no difference in assertions
describe('user shape', () => {
  it('has an id and name', () => {
    expect(mockUser).toEqual(jasmine.objectContaining({ id: 0 }));
    expect(mockUserT.name).toBe('Test User');
  });
});
